320x50.manualCss:
/* ── Shared typography ── */
.sse-text {
  position: absolute;
  font-family: Museo, Arial, sans-serif;
  color: rgb(0, 41, 117);
}

.sse-text-heavy {
  font-weight: 900;
}

.sse-text-bold {
  font-weight: 700;
}

/* ── OfferSlot group plumbing ── */
[data-gwd-group="OfferSlot"] {
  width: 100%;
  height: 100%;
}

[data-gwd-group="OfferSlot"] .gwd-grp-offer {
  position: absolute;
  font-family: Museo, Arial, sans-serif;
  font-weight: 700;
  color: rgb(0, 41, 117);
  visibility: inherit;
}

[data-gwd-group="OfferSlot"] .offer-value .sym-pct {
  font-size: 0.6em;
  vertical-align: baseline;
  position: relative;
  /* Vertical offset computed at runtime from glyph metrics
     (alignPercentSymbols) so the % bottom-aligns with the digits. */
}

/* ── T&C group plumbing ── */
[data-gwd-group="tc_prices"] .gwd-grp-tc.sse-text,
[data-gwd-group="tc_solo"] .gwd-grp-tc.sse-text {
  position: absolute;
  font-family: Museo, Arial, sans-serif;
  color: rgb(0, 41, 117);
}

/* Feed text uses \n for forced breaks (e.g. two-line unit rate). */
.terms-prices,
.terms-solo,
.unit-rate-prices {
  white-space: pre-line;
}

/* ── T&C wrappers (far-left tiny zone) ── */
.tc-prices-group,
.tc-solo-group {
  position: absolute;
}

.roundel-frame-off #headline-act3 { visibility: hidden; }

/* Act 4 only: white over blue wave on 320×50 */
#headline-act4 {
  color: rgb(255, 255, 255);
  top: 9px;
}

